export function buildSceneBackdropCatalog(
    baseCatalog = BASE_SCENE_BACKDROP_CATALOG,
    plannedCatalog = PLANNED_SCENE_BACKDROPS,
    externalAdultCatalog = externalGrokAdultSceneBackdrops,
) {
    const plannedByKey = new Map(plannedCatalog.filter((item) => item?.key).map((item) => [item.key, item]));
    const mergedBase = baseCatalog.map((item) => {
        const planned = plannedByKey.get(item?.key);
        if (!planned) {
            return item;
        }
        return {
            ...item,
            imageUrl: item.imageUrl || planned.imageUrl,
            file: item.file || planned.file,
            source: item.source || planned.source,
            keywords: Array.from(new Set([...(item.keywords || []), ...(planned.keywords || [])])),
            tags: Array.from(new Set([...(item.tags || []), ...(planned.tags || [])])),
            generatedPrompt: planned.prompt,
        };
    });
    const baseKeys = new Set(mergedBase.map((item) => item?.key).filter(Boolean));
    const planned = plannedCatalog.filter((item) => item?.key && !baseKeys.has(item.key));
    const usedKeys = new Set([...baseKeys, ...planned.map((item) => item.key)]);
    const externalAdult = externalAdultCatalog.filter((item) => item?.key && !usedKeys.has(item.key));
    return [
        ...mergedBase,
        ...planned,
        ...externalAdult,
    ];
}

export function buildSceneBackdropIndex(catalog = []) {
    return Object.fromEntries(catalog.filter((item) => item?.key).map((item) => [item.key, item]));
}

export const sceneBackdropCatalog = buildSceneBackdropCatalog();
export const sceneBackdropByKey = buildSceneBackdropIndex(sceneBackdropCatalog);
